9	
10	export const useProfileStore = defineStore("profile", {
11	  state: () => ({
12	    errors: {},
13	    profile: {}
14	  }),
15	  actions: {
16	    async fetchProfile({ username }) {
17	      // Profiles can be briefly missing right after registration on an
18	      // eventually-consistent backend, so retry before declaring an error.
19	      for (let attempt = 0; ; attempt++) {
20	        try {
21	          const { data } = await ApiService.get("profiles", username);
22	          this.profile = data.profile;
23	          this.errors = {};
24	          return data;
25	        } catch (error) {
26	          if (attempt >= PROFILE_FETCH_RETRIES) {
27	            this.profile = {};
28	            this.errors = extractErrors(error);
29	            return;
30	          }
31	          await delay(PROFILE_FETCH_RETRY_DELAY);
32	        }
33	      }
34	    },
35	    async follow({ username }) {
36	      try {
37	        const { data } = await ApiService.post(`profiles/${username}/follow`);
38	        this.profile = data.profile;
39	        this.errors = {};
40	        return data;
41	      } catch {
42	        // Leave the profile as-is; the follow button simply stays unchanged.
43	      }
44	    },
45	    async unfollow({ username }) {
46	      try {
47	        const { data } = await ApiService.delete(`profiles/${username}/follow`);
48	        this.profile = data.profile;
